-- 00125_mock_replay.sql — Phase K Wave 15 (2026-05-14)
--
-- Pipeline-attempt replay: a per-attempt "ideal answer" + structured diff
-- annotations that power the post-debrief MockReplay page. Generated by
-- the free LLM cascade on first user request (lazy), cached in-row so
-- subsequent views are O(SELECT).
--
-- Schema rationale:
--   - ideal_answer_md  TEXT — Markdown body, 200-400 words; the "how
--                     could you have answered" reference. NULL when not
--                     yet generated.
--   - diff_annotations JSONB — Array of objects:
--       {your_excerpt, ideal_excerpt, type: "missing"|"incorrect"|"good",
--        comment}
--     Frontend renders these as side-by-side highlights. Empty array
--     means "no diff to show" (perfect answer / generation failed).
--   - replay_generated_at TIMESTAMPTZ — Stamp when the LLM produced the
--                     pair. NULL ⇢ never generated. Doubles as cache
--                     freshness signal (regen if columns change in a
--                     migration but model doesn't bump).
--
-- All three are added to pipeline_attempts (the existing per-answer row
-- under each pipeline stage; see backend/migrations/00001_baseline.sql).
-- Stale columns are nullable to keep backfill trivial.

-- +goose Up
-- +goose StatementBegin

ALTER TABLE pipeline_attempts
    ADD COLUMN IF NOT EXISTS ideal_answer_md       TEXT,
    ADD COLUMN IF NOT EXISTS diff_annotations      JSONB,
    ADD COLUMN IF NOT EXISTS replay_generated_at   TIMESTAMPTZ;

-- Partial index — most queries fetch by id, but we occasionally batch-list
-- attempts with cached replays to avoid LLM hits on debrief navigation
-- between stages.
CREATE INDEX IF NOT EXISTS pipeline_attempts_replay_gen_at_idx
    ON pipeline_attempts (replay_generated_at)
    WHERE replay_generated_at IS NOT NULL;

-- +goose StatementEnd

-- +goose Down
-- +goose StatementBegin

DROP INDEX IF EXISTS pipeline_attempts_replay_gen_at_idx;
ALTER TABLE pipeline_attempts
    DROP COLUMN IF EXISTS replay_generated_at,
    DROP COLUMN IF EXISTS diff_annotations,
    DROP COLUMN IF EXISTS ideal_answer_md;

-- +goose StatementEnd
